import React from 'react';
import { ArrowRight } from 'lucide-react';

function HeroContent({ t, scrollToSection }) {
  return (
    <div className="relative z-10 text-left max-w-xl">
      <h1 className="text-4xl sm:text-5xl md:text-6xl font-black text-white mb-4 leading-tight">
        {t.hero.title.split('&')[0]}
        <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-400 to-cyan-400">
          {t.hero.title.includes('&') ? '& ' + t.hero.title.split('&')[1] : ''}
        </span>
      </h1>

      <h2 className="text-3xl sm:text-4xl font-bold text-emerald-400 mb-6">
        {t.hero.subtitle}
      </h2>

      <p className="text-lg text-blue-100/80 mb-8 leading-relaxed">
        {t.hero.description}
      </p>

      <div className="flex flex-col sm:flex-row gap-4">
        <button 
          onClick={() => window.location.href = '/contact'} 
          className="group bg-gradient-to-r from-orange-500 to-red-500 text-white px-8 py-4 rounded-xl font-bold text-lg hover:from-orange-600 hover:to-red-600 transition-all flex items-center justify-center space-x-2 hover:scale-105 shadow-xl"
        >
          <span>{t.hero.btnCTA}</span>
          <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
        </button>

        <button 
          onClick={() => scrollToSection('portfolio')} 
          className="bg-white/10 backdrop-blur-sm border-2 border-white/30 text-white px-8 py-4 rounded-xl font-bold text-lg hover:bg-white/20 transition-all hover:scale-105"
        >
          {t.hero.btnPortfolio}
        </button>
      </div>
    </div>
  );
}

export default HeroContent;
